// ─── GOOGLE SHEET CONFIG ─────────────────────────────────────────────────────
// ─── STUDENT DATABASE — Live sync from Google Sheet ─────────────────────────
// Uses the published CSV URL — works from any browser without CORS issues.
// REQUIRED ONE-TIME SETUP in Google Sheet:
//   File → Share → Publish to web → Sheet1 → CSV → Publish → OK
// After publishing, the URL below will always return live data.

const SHEET_ID = "1IUw6O-7XuvDvEB0tcaYlnYAMYnHpzWHAoGdYLCv-2cw";
// Direct CSV export URL — works when sheet is shared as "Anyone with link can view"
const SHEET_CSV_URL = `https://docs.google.com/spreadsheets/d/${SHEET_ID}/export?format=csv&gid=0`;

const parseCSV = (text) => {
  const lines = text.trim().split("\n").filter(l => l.trim());
  return lines.slice(1).map(line => {
    const cols = [];
    let cur = "", inQ = false;
    for (const ch of line) {
      if (ch === '"') { inQ = !inQ; }
      else if (ch === "," && !inQ) { cols.push(cur.trim()); cur = ""; }
      else { cur += ch; }
    }
    cols.push(cur.trim());
    return {
      sno:    cols[0] ?? "",
      name:   (cols[1] ?? "").trim(),
      phone:  (cols[2] ?? "").replace(/\D/g, ""),
      email:  (cols[3] ?? "").trim(),
      course: (cols[4] ?? "").trim(),
    };
  }).filter(s => s.name);
};

const fetchStudents = async () => {
  // Method 1: Direct fetch (works on Vercel-hosted app, no CORS issue there)
  try {
    const res = await fetch(SHEET_CSV_URL, { cache: "no-cache" });
    if (res.ok) {
      const text = await res.text();
      const students = parseCSV(text);
      if (students.length > 0) {
        console.log("✓ Sheet loaded directly:", students.length, "students");
        return students;
      }
    }
  } catch (e) {
    console.warn("Direct fetch failed:", e.message);
  }

  // Method 2: fallback — try direct CSV again with no-cache
  try {
    const res = await fetch(SHEET_CSV_URL + "&t=" + Date.now(), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        system: `You are a data tool. Fetch this Google Sheets CSV URL and return ONLY a JSON array, no markdown, no explanation.
Each item must have: sno, name, phone, email, course.
Skip the header row. Example: [{"sno":"1","name":"alim","phone":"7904082982","email":"x@y.com","course":"ms office"}]`,
        message: `Fetch and return student data from: ${SHEET_CSV_URL}`,
      }),
    });
    if (res.ok) {
      const data = await res.json();
      const text = (data.text || "").replace(/\`\`\`json|\`\`\`/g, "").trim();
      const students = JSON.parse(text);
      if (Array.isArray(students) && students.length > 0) {
        console.log("✓ Sheet loaded via proxy:", students.length, "students");
        return students.map(s => ({
          sno: String(s.sno ?? ""), name: String(s.name ?? "").trim(),
          phone: String(s.phone ?? "").replace(/\D/g, ""),
          email: String(s.email ?? "").trim(), course: String(s.course ?? "").trim(),
        })).filter(s => s.name);
      }
    }
  } catch (e) {
    console.warn("Proxy fetch failed:", e.message);
  }

  throw new Error("Could not load student data. Please check your internet connection.");
};

// ─── LOGIN SCREEN ─────────────────────────────────────────────────────────────
const LoginScreen = ({ onLogin }) => {
  const [phone, setPhone]       = useState("");
  const [password, setPassword] = useState("");
  const [showPass, setShowPass] = useState(false);
  const [error, setError]       = useState("");
  const [loading, setLoading]   = useState(false);
  const [step, setStep]         = useState("phone"); // "phone" | "password"
  const [student, setStudent]   = useState(null);

  // Password rule: first 4 letters of name (lowercase) + last 4 digits of phone
  const getExpectedPassword = (name, ph) => {
    const letters = name.replace(/\s+/g, "").toLowerCase().slice(0, 4);
    const digits  = ph.replace(/\D/g, "").slice(-4);
    return letters + digits;
  };

  const handlePhoneNext = async () => {
    setError("");
    const cleaned = phone.replace(/\D/g, "");
    if (cleaned.length < 10) { setError("Please enter a valid 10-digit phone number."); return; }
    setLoading(true);
    try {
      const students = await fetchStudents();
      console.log("Fetched students:", students);
      if (!students || students.length === 0) {
        setError("⚠️ Student database is empty. Check your Google Sheet has data.");
        setLoading(false); return;
      }
      // Match by last 10 digits of phone
      const match = students.find(s => {
        const sp = s.phone.replace(/\D/g, "").slice(-10);
        console.log("Comparing:", sp, "vs", cleaned.slice(-10));
        return sp === cleaned.slice(-10);
      });
      if (!match) {
        setError("📋 Phone number not registered yet. Tap \"Register Now\" below to join Allbee — then log in once added.");
        setLoading(false); return;
      }
      setStudent(match);
      setStep("password");
    } catch (e) {
      console.error("fetchStudents error:", e);
      setError("❌ Something went wrong. Please try again.");
    }
    setLoading(false);
  };

  const handlePasswordLogin = async () => {
    setError("");
    if (!password) { setError("Please enter your password."); return; }
    const expected = getExpectedPassword(student.name, student.phone);
    if (password !== expected) {
      setError("Incorrect password. Password = first 4 letters of your name + last 4 digits of your phone.");
      return;
    }
    setLoading(true);
    setTimeout(async () => {
      const user = {
        name:   student.name,
        phone:  student.phone,
        email:  student.email,
        course: student.course,
        avatar: student.name[0].toUpperCase(),
      };
      localStorage.setItem(USER_KEY, JSON.stringify(user));
      onLogin(user);
    }, 700);
  };

  const handleKey = (e) => {
    if (e.key !== "Enter") return;
    if (step === "phone") handlePhoneNext();
    else handlePasswordLogin();
  };

  return (
    <div style={{ minHeight: "100vh", background: "linear-gradient(135deg, #e0f7fa 0%, #ffffff 50%, #b2ebf2 100%)", display: "flex", alignItems: "center", justifyContent: "center", padding: "20px", position: "relative", overflow: "hidden" }}>
      <div style={{ position: "absolute", top: "-80px", right: "-80px", width: "300px", height: "300px", background: "radial-gradient(circle, rgba(0,188,212,0.15) 0%, transparent 70%)", borderRadius: "50%", pointerEvents: "none" }} />
      <div style={{ position: "absolute", bottom: "-60px", left: "-60px", width: "250px", height: "250px", background: "radial-gradient(circle, rgba(0,172,193,0.1) 0%, transparent 70%)", borderRadius: "50%", pointerEvents: "none" }} />

      <div className="card fade-in" style={{ maxWidth: 420, width: "100%", padding: "40px 36px", textAlign: "center", zIndex: 1 }}>

        {/* Logo */}
        <div style={{ marginBottom: 24 }}>
          <div style={{ width: 100, height: 100, background: "#000", borderRadius: 20, display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 14px", boxShadow: "0 8px 24px rgba(0,0,0,0.25)", overflow: "hidden" }}>
            <img src={LOGO_SRC} alt="Allbee Solutions" style={{ width: 80, height: 80, objectFit: "contain" }} />
          </div>
          <h1 style={{ fontFamily: "'Plus Jakarta Sans', sans-serif", fontSize: 24, fontWeight: 800, color: "var(--slate-900)", letterSpacing: "-0.02em" }}>
            Allbee Learn <span style={{ color: "var(--blue-600)" }}>AI</span>
          </h1>
          <p style={{ color: "var(--slate-500)", fontSize: 13, marginTop: 5 }}>Student Login — Free AI learning 🎓</p>
        </div>

        <div style={{ height: 1, background: "var(--slate-100)", margin: "20px 0" }} />

        {/* Step indicators */}
        <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 8, marginBottom: 24 }}>
          {["Phone", "Password"].map((label, i) => {
            const active = (i === 0 && step === "phone") || (i === 1 && step === "password");
            const done   = i === 0 && step === "password";
            return (
              <div key={label} style={{ display: "flex", alignItems: "center", gap: 8 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                  <div style={{ width: 24, height: 24, borderRadius: "50%", background: done ? "var(--green-500)" : active ? "var(--blue-600)" : "var(--slate-200)", color: "white", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: 700, transition: "all 0.3s" }}>
                    {done ? "✓" : i + 1}
                  </div>
                  <span style={{ fontSize: 12, fontWeight: active ? 700 : 400, color: active ? "var(--slate-800)" : "var(--slate-400)" }}>{label}</span>
                </div>
                {i === 0 && <div style={{ width: 32, height: 2, background: step === "password" ? "var(--blue-600)" : "var(--slate-200)", borderRadius: 99, transition: "all 0.3s" }} />}
              </div>
            );
          })}
        </div>

        {/* Step 1 — Phone */}
        {step === "phone" && (
          <div className="fade-in">
            <div style={{ textAlign: "left", marginBottom: 16 }}>
              <div className="section-label">Registered Phone Number</div>
              <input
                placeholder="Enter your phone number..."
                value={phone}
                onChange={e => { setPhone(e.target.value); setError(""); }}
                onKeyDown={handleKey}
                inputMode="numeric"
                style={{ fontSize: 15 }}
                autoFocus
              />
              <p style={{ fontSize: 12, color: "var(--slate-400)", marginTop: 8 }}>
                📋 Use the phone number you registered with Allbee Solutions.
              </p>
            </div>

            {error && <div style={{ background: "var(--red-50)", border: "1px solid #fecaca", borderRadius: "var(--radius-sm)", padding: "10px 14px", marginBottom: 14, fontSize: 13, color: "var(--red-500)", textAlign: "left" }}>⚠️ {error}</div>}

            <button className="btn-primary" style={{ width: "100%", justifyContent: "center" }} onClick={handlePhoneNext} disabled={loading}>
              {loading ? <><span className="spinner" /> Checking...</> : <>Next →</>}
            </button>
          </div>
        )}

        {/* Step 2 — Password */}
        {step === "password" && student && (
          <div className="fade-in">
            {/* Student found card */}
            <div style={{ background: "var(--blue-50)", border: "1.5px solid var(--blue-200)", borderRadius: "var(--radius)", padding: "12px 16px", marginBottom: 18, display: "flex", alignItems: "center", gap: 12, textAlign: "left" }}>
              <div style={{ width: 40, height: 40, background: "var(--blue-600)", borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", color: "white", fontWeight: 800, fontSize: 16, flexShrink: 0 }}>
                {student.name[0].toUpperCase()}
              </div>
              <div>
                <div style={{ fontWeight: 700, fontSize: 14, color: "var(--slate-800)" }}>{student.name}</div>
                <div style={{ fontSize: 12, color: "var(--slate-500)" }}>{student.course} · ✅ Registered</div>
              </div>
            </div>

            <div style={{ textAlign: "left", marginBottom: 6 }}>
              <div className="section-label">Password</div>
              <div style={{ position: "relative" }}>
                <input
                  placeholder="Enter your password..."
                  type={showPass ? "text" : "password"}
                  value={password}
                  onChange={e => { setPassword(e.target.value); setError(""); }}
                  onKeyDown={handleKey}
                  style={{ fontSize: 15, paddingRight: 48 }}
                  autoFocus
                />
                <button onClick={() => setShowPass(p => !p)} style={{ position: "absolute", right: 14, top: "50%", transform: "translateY(-50%)", background: "none", border: "none", cursor: "pointer", color: "var(--slate-400)", fontSize: 18, padding: 0, lineHeight: 1 }}>
                  {showPass ? "🙈" : "👁️"}
                </button>
              </div>
              <p style={{ fontSize: 12, color: "var(--slate-400)", marginTop: 8, lineHeight: 1.6 }}>
                💡 Password = first 4 letters of name + last 4 digits of phone<br/>
                <span style={{ color: "var(--slate-300)" }}>
                  Example: <code style={{ background: "var(--slate-100)", padding: "1px 5px", borderRadius: 4, color: "var(--slate-600)" }}>
                    {student.name.replace(/\s+/g,"").toLowerCase().slice(0,4)}{student.phone.replace(/\D/g,"").slice(-4)}
                  </code>
                </span>
              </p>
            </div>

            {error && <div style={{ background: "var(--red-50)", border: "1px solid #fecaca", borderRadius: "var(--radius-sm)", padding: "10px 14px", marginBottom: 14, fontSize: 13, color: "var(--red-500)", textAlign: "left" }}>⚠️ {error}</div>}

            <div style={{ display: "flex", gap: 10, marginTop: 16 }}>
              <button className="btn-secondary" onClick={() => { setStep("phone"); setPassword(""); setError(""); setStudent(null); }} style={{ flex: 1, justifyContent: "center" }}>← Back</button>
              <button className="btn-primary" style={{ flex: 2, justifyContent: "center" }} onClick={handlePasswordLogin} disabled={loading}>
                {loading ? <><span className="spinner" /> Logging in...</> : <>Login →</>}
              </button>
            </div>
          </div>
        )}

        {/* New student registration */}
        <div style={{ height: 1, background: "var(--slate-100)", margin: "22px 0 16px" }} />
        <div style={{ fontSize: 12.5, color: "var(--slate-500)", marginBottom: 10 }}>
          New to Allbee? Enroll for a course first 👇
        </div>
        <button
          onClick={openRegister}
          style={{ width: "100%", justifyContent: "center", display: "flex", alignItems: "center", gap: 8, background: "white", color: "var(--blue-700)", border: "1.5px solid var(--blue-200)", borderRadius: "var(--radius)", padding: "12px 20px", fontSize: 15, fontWeight: 700 }}
        >
          📝 Register Now — It's Free
        </button>
        <p style={{ fontSize: 11.5, color: "var(--slate-400)", marginTop: 12, lineHeight: 1.6 }}>
          After you register, Allbee adds you to the student list — then log in with your phone number 🎓
        </p>
      </div>
    </div>
  );
};

