// ─── MS OFFICE SCREEN ────────────────────────────────────────────────────────
const MSOfficeScreen = ({ onBack }) => {
  const [activeApp, setActiveApp] = useState("word");
  const [input, setInput] = useState("");
  const [output, setOutput] = useState("");
  const [loading, setLoading] = useState(false);
  const [copied, setCopied] = useState(false);
  const [error, setError] = useState("");
  const outputRef = useRef(null);

  const app = officeApps.find(a => a.id === activeApp);

  const handleSubmit = async () => {
    if (!input.trim()) { setError("Please enter your question!"); return; }
    setError(""); setLoading(true); setOutput("");
    try {
      const result = await callClaude(PROMPTS[activeApp], input.trim());
      setOutput(result);
      saveHistory({ feature: "msoffice", subFeature: activeApp, input: `[${app.label}] ${input.trim()}`, output: result });
      setTimeout(() => outputRef.current?.scrollIntoView({ behavior: "smooth", block: "start" }), 100);
    } catch (e) { setError("Error: " + (e.message || "Something went wrong. Try again!")); }
    setLoading(false);
  };

  const handleCopy = () => { navigator.clipboard.writeText(output); setCopied(true); setTimeout(() => setCopied(false), 2000); };

  const handleSuggestion = (s) => { setInput(s); setOutput(""); setError(""); };

  const switchApp = (id) => { setActiveApp(id); setInput(""); setOutput(""); setError(""); };

  const renderOutput = (text) => {
    if (!text) return null;
    return text.split("\n").map((line, i) => {
      if (line.startsWith("```")) return null;
      const parts = line.split(/(`[^`]+`)/g);
      return (
        <div key={i} style={{ marginBottom: line === "" ? 8 : 2, lineHeight: 1.75 }}>
          {parts.map((p, j) =>
            p.startsWith("`") && p.endsWith("`")
              ? <code key={j}>{p.slice(1, -1)}</code>
              : <span key={j}>{p}</span>
          )}
        </div>
      );
    });
  };

  return (
    <div style={{ maxWidth: 800, margin: "0 auto", padding: "0 16px 100px" }}>
      {/* Header */}
      <div style={{ paddingTop: 20, paddingBottom: 16, display: "flex", alignItems: "center", gap: 14 }}>
        <button onClick={onBack} style={{ background: "var(--slate-100)", border: "none", borderRadius: "var(--radius-sm)", width: 36, height: 36, display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer" }}>
          <Icon name="back" size={18} color="var(--slate-600)" />
        </button>
        <div style={{ width: 40, height: 40, background: "#e8f0fe", borderRadius: 10, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20 }}>🖥️</div>
        <div>
          <div style={{ fontFamily: "'Plus Jakarta Sans', sans-serif", fontSize: 17, fontWeight: 800, color: "var(--slate-900)" }}>MS Office Helper</div>
          <div style={{ fontSize: 12, color: "var(--slate-400)" }}>Word · Excel · PowerPoint — எல்லாம் கத்துக்கலாம்!</div>
        </div>
      </div>

      {/* App switcher tabs */}
      <div style={{ display: "flex", gap: 8, marginBottom: 18 }}>
        {officeApps.map(a => (
          <button key={a.id} onClick={() => switchApp(a.id)} style={{ flex: 1, padding: "10px 8px", borderRadius: "var(--radius)", border: "2px solid", cursor: "pointer", transition: "all 0.2s", fontFamily: "'Plus Jakarta Sans', sans-serif", fontWeight: 700, fontSize: 13, display: "flex", flexDirection: "column", alignItems: "center", gap: 4,
            borderColor: activeApp === a.id ? a.color : "var(--slate-200)",
            background: activeApp === a.id ? a.bg : "white",
            color: activeApp === a.id ? a.color : "var(--slate-500)",
            boxShadow: activeApp === a.id ? `0 0 0 3px ${a.color}20` : "none"
          }}>
            <span style={{ fontSize: 20 }}>{a.emoji}</span>
            <span className="hide-mobile">{a.label}</span>
            <span style={{ display: "none" }} className="show-mobile">{a.label.split(" ")[1] || a.label}</span>
          </button>
        ))}
      </div>

      {/* Quick suggestion chips */}
      <div className="card fade-in" style={{ padding: "16px 18px", marginBottom: 14 }}>
        <div className="section-label">Quick Questions — tap to ask</div>
        <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginTop: 4 }}>
          {app.subs.map(s => (
            <button key={s} onClick={() => handleSuggestion(`How to ${s} in ${app.label}?`)} style={{ padding: "6px 13px", borderRadius: 99, fontSize: 12.5, fontWeight: 500, border: `1.5px solid ${app.color}30`, background: app.bg, color: app.color, cursor: "pointer", transition: "all 0.18s", display: "flex", alignItems: "center", gap: 5 }}>
              {app.emoji} {s}
            </button>
          ))}
        </div>
      </div>

      {/* Input area */}
      <div className="card" style={{ padding: "18px 18px 14px", marginBottom: 14 }}>
        <div className="section-label">Your Question</div>
        <textarea
          value={input}
          onChange={e => { setInput(e.target.value); setError(""); }}
          placeholder={`Ask anything about ${app.label}...\n\nExamples:\n• How to create a table in ${app.label}?\n• ${activeApp === "excel" ? "VLOOKUP formula எப்படி use பண்றது?" : activeApp === "ppt" ? "Slide transition எப்படி add பண்றது?" : "Mail merge எப்படி பண்றது?"}`}
          rows={4}
          style={{ fontSize: 14.5, marginBottom: 10 }}
        />
        {error && <div style={{ color: "var(--red-500)", fontSize: 13, marginBottom: 10, padding: "8px 12px", background: "var(--red-50)", borderRadius: "var(--radius-sm)" }}>⚠️ {error}</div>}
        <div style={{ display: "flex", gap: 10, justifyContent: "flex-end" }}>
          <button className="btn-secondary" onClick={() => { setInput(""); setOutput(""); }}>Clear</button>
          <button className="btn-primary" onClick={handleSubmit} disabled={loading} style={{ background: app.color }}>
            {loading ? <><span className="spinner" /> Thinking...</> : <><Icon name="send" size={16} color="white" /> Get Answer</>}
          </button>
        </div>
      </div>

      {/* Loading */}
      {loading && (
        <div className="card fade-in" style={{ padding: 28, textAlign: "center" }}>
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 12 }}>
            <div style={{ fontSize: 36, animation: "pulse 1.5s infinite" }}>{app.emoji}</div>
            <div style={{ fontWeight: 600, color: "var(--slate-700)" }}>{app.label} answer தயார் பண்றேன்...</div>
            <div style={{ display: "flex", gap: 6 }}>
              {[0,1,2].map(i => <div key={i} style={{ width: 8, height: 8, borderRadius: "50%", background: app.color, animation: `pulse 1.4s ease ${i*0.2}s infinite` }} />)}
            </div>
          </div>
        </div>
      )}

      {/* Output */}
      {output && !loading && (
        <div ref={outputRef} className="card fade-in" style={{ padding: 20 }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 14 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <div style={{ width: 8, height: 8, background: "var(--green-500)", borderRadius: "50%" }} />
              <div className="section-label" style={{ marginBottom: 0 }}>{app.emoji} {app.label} — Allbee AI Answer</div>
            </div>
            <button onClick={handleCopy} className="btn-ghost" style={{ fontSize: 13, display: "flex", alignItems: "center", gap: 6 }}>
              {copied ? <><Icon name="check" size={14} color="var(--green-500)" /><span style={{ color: "var(--green-500)" }}>Copied!</span></> : <><Icon name="copy" size={14} /> Copy</>}
            </button>
          </div>
          <div className="output-box">{renderOutput(output)}</div>
          <div style={{ marginTop: 14, display: "flex", gap: 10, flexWrap: "wrap", alignItems: "center" }}>
            <button className="btn-secondary" onClick={() => { setInput(""); setOutput(""); }} style={{ fontSize: 13 }}>🔄 Ask Another</button>
            <div style={{ flex: 1 }} />
            <div style={{ fontSize: 12, color: "var(--slate-400)" }}>✅ Saved to History</div>
          </div>
        </div>
      )}
    </div>
  );
};


